// --- MERGE SYNC LOGIC ---
let mergeTargets = [];

async function initMergeSync() {
    const funcName = document.getElementById('ef-name').value.trim();
    const code = document.getElementById('ef-code').value.trim();
    if (!funcName || !code || code === "Loading...") return showGlobalToast("Function name and code required", true);

    document.getElementById('merge-sync-overlay').classList.add('active');
    document.getElementById('merge-status-text').innerText = `Scanning your repositories for 'supabase/functions/${funcName}'...`;
    document.getElementById('merge-checklist-header').style.display = 'none';
    document.getElementById('btn-execute-merge').style.display = 'none';
    document.getElementById('merge-log').innerHTML = '';
    document.getElementById('merge-progress-container').style.display = 'none';

    try {
        const res = await fetch(CONFIG.funcUrl, { 
            method: 'POST', 
            headers: {'Content-Type': 'application/json'}, 
            body: apiBody({ action: 'fetch_repos' }) 
        });
        const data = await res.json();
        const repos = data.repos || [];

        mergeTargets = [];
        const path = `supabase/functions/${funcName}/index.ts`;

        const checks = await Promise.all(repos.map(async (r) => {
            if (r.name === CONFIG.repoName) return null;
            try {
                const checkRes = await fetch(CONFIG.funcUrl, { 
                    method: 'POST', 
                    headers: {'Content-Type': 'application/json'}, 
                    body: apiBody({ action: 'preview_file', repo_name: r.name, file_path: path }) 
                });
                const checkData = await checkRes.json();
                if (checkData.sha) return r;
            } catch(e) { return null; }
            return null;
        }));

        mergeTargets = checks.filter(r => r !== null);

        if (mergeTargets.length === 0) {
            document.getElementById('merge-status-text').innerText = "No other repositories contain this edge function. Merge cancelled.";
            return;
        }

        document.getElementById('merge-status-text').innerText = `Found ${mergeTargets.length} repositories with a matching function. Select targets to update:`;
        renderMergeChecklist();
        document.getElementById('merge-checklist-header').style.display = 'block';
        document.getElementById('btn-execute-merge').style.display = 'block';
        document.getElementById('btn-execute-merge').innerText = "Start Sync";
        document.getElementById('btn-execute-merge').onclick = executeGlobalMerge;

    } catch (e) {
        document.getElementById('merge-status-text').innerText = "Error scanning repositories: " + e.message;
    }
}

function renderMergeChecklist() {
    const container = document.getElementById('merge-checklist-container');
    container.innerHTML = mergeTargets.map((r, i) => `
        <label class="filter-checkbox-item">
            <input type="checkbox" class="merge-target-check" value="${r.name}" checked style="accent-color:var(--prod)">
            <div style="display:flex; flex-direction:column; margin-left:10px;">
                <span style="font-weight:600; color:#eee;">${r.name}</span>
            </div>
        </label>
    `).join('');
}

function toggleAllMergeTargets(checked) {
    document.querySelectorAll('.merge-target-check').forEach(cb => cb.checked = checked);
}

function closeMergeSync() {
    document.getElementById('merge-sync-overlay').classList.remove('active');
}

async function executeGlobalMerge() {
    const selected = Array.from(document.querySelectorAll('.merge-target-check:checked')).map(cb => cb.value);
    if (selected.length === 0) return alert("Select at least one repository.");

    const funcName = document.getElementById('ef-name').value.trim();
    const code = document.getElementById('ef-code').value.trim();
    const path = `supabase/functions/${funcName}/index.ts`;

    if (!confirm(`Broadcast this logic to ${selected.length} repositories? This will create new commits in each.`)) return;

    const syncBtn = document.getElementById('btn-execute-merge');
    syncBtn.disabled = true;
    document.getElementById('merge-progress-container').style.display = 'block';
    const log = document.getElementById('merge-log');

    for (const repo of selected) {
        const line = document.createElement('div');
        line.style.marginBottom = '4px';
        line.innerHTML = `<span style="color:var(--text-muted)">[SYNCING]</span> ${repo}...`;
        log.appendChild(line);
        log.scrollTop = log.scrollHeight;

        try {
            const ops = [
                { "action": "comment", "text": `[Global Merge] Sync '${funcName}' from ${CONFIG.repoName}` },
                { "action": "create_file", "file_path": path, "content": code }
            ];

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'patch', repo_name: repo, operations: ops })
            });
            const data = await res.json();

            if (data.success) {
                line.innerHTML = `<span style="color:var(--prod)">[SUCCESS]</span> ${repo} updated. (SHA: ${data.commit_sha.substring(0,7)})`;
            } else {
                throw new Error(data.error || "Patch failed");
            }
        } catch (e) {
            line.innerHTML = `<span style="color:var(--danger)">[FAILED]</span> ${repo}: ${e.message}`;
        }
    }

    document.getElementById('merge-status-text').innerText = "Global Merge Complete.";
    syncBtn.innerText = "Done";
    syncBtn.onclick = closeMergeSync;
    syncBtn.disabled = false;

    fetchState(false, true);
}

